head.script:
//------------------
// global variable
//------------------
scwin.strId = ""; 
scwin.strEmpNm = ""; 
scwin.strCopNm = ""; 
scwin.strRegNo = ""; 
scwin.strTel = ""; 
scwin.gubun = ""; 
scwin.strEmc = ""; 
scwin.stref = ""; 

scwin.MSG_OP_INF_001 = "D/O, B/L을 자동으로 가져오려면\n컨테이너번호는 필수입력사항입니다.";
scwin.MSG_OP_INF_002 = "D/O, B/L을 자동으로 가져오려면\nOPERATOR는 필수입력사항입니다.";
scwin.MSG_OP_INF_003 = "존재하지 않는 B/L입니다.\n다시 확인하여 입력하십시오.";
scwin.MSG_OP_INF_004 = "B/L NO와 D/O NO의 값이 서로 일치하지 않습니다.\nB/L NO와 D/O NO는 동일한 값을 입력하세요.";

scwin.arrRtnVal         = new Array(); // Return Value
scwin.gv_strExistTF     = ""; // 중복체크여부
scwin.arrParent         = new Array();
scwin.gv_userClsCd      = $c.data.getMemInfo("userClsCd");
scwin.gv_clntNo         = $c.data.getMemInfo("clntNo");
scwin.gv_clntNm         = $c.data.getMemInfo("clntNm");
scwin.dateServer        = $c.date.getServerDateTime("yyyyMMddHHmmss"); 
scwin.dateStr           = scwin.dateServer.substring(0, 8);
scwin.dateTime          = scwin.dateServer.substring(8, 12);
scwin.strCurYear        = scwin.dateServer.substring(0, 4);

//------------------
// function
//------------------
scwin.onpageload = function () {

    setTimeout(function() { 
        wf_title.scope.txt_h1.setValue('EVER 반출입예정정보EDI강제등록 ');
        wf_title.setStyle('visibility', 'visible')
    }, 150);


    td_sndDtHh1.setValue("");
    td_sndDtHh2.setValue("");

    var params = $c.data.getParameter(); 

    scwin.strId = params.strId == null ? "" : params.strId; 
    scwin.strEmpNm = params.strEmpNm == null ? "" : params.strEmpNm; 
    scwin.strCopNm = params.strCopNm == null ? "" : params.strCopNm; 
    scwin.strRegNo = params.strRegNo == null ? "" : params.strRegNo; 
    scwin.strTel = params.strTel == null ? "" : params.strTel; 
    scwin.gubun = params.gubun == null ? "" : params.gubun; 
    scwin.strEmc = params.strEmc == null ? "" : params.strEmc; 
    scwin.stref = params.stref == null ? "" : params.stref; 

    scwin.f_setDsSearchHeader();

    // DataSet 초기화
    ds_search.setEmptyValue();

    ds_resultsCopinoOut.removeAll(); // 반출(COPINO) DataSet 초기화
    ds_resultsCopinoOut.insertRow();
    ds_resultsCopinoOut.setRowPosition(0);

    ds_resultsCopinoIn.removeAll(); // 반입(COPINO) DataSet 초기화
    ds_resultsCopinoIn.insertRow();
    ds_resultsCopinoIn.setRowPosition(0);

    scwin.f_defaultValue();

    ed_sealNo2.options.mandatory    = false;
    ed_sealNo2.setReadOnly(false);
    lbl_sealNo2.removeClass("req");

    td_sndClsCd1.setValue(""); 
    td_sndClsCd2.setValue(""); 

    // 컴포넌트 초기 설정
}


scwin.onUdcCompleted = function() {
    var v_strRegNo = scwin.strRegNo; 
    var stref1 = scwin.stref;
    var curDate = scwin.dateStr; 

    if (stref1 == "M") { 
        cbx_crryInCopino.setValue("Y");
        $c.gus.cfEnableObjects([tb_crryInCopino]);
        $c.gus.cfDisableObjects([tb_crryOutCopino]);
        ds_resultsCopinoOut.removeAll(); // 반출(COPINO) DataSet 초기화

        ed_tmlVsslPortcnt2.setValue("ODEM" + curDate.substring(4, 6));
        ed_dchrPort2.setValue("ZZZZZ");

    } else {
        cbx_crryOutCopino.setValue("")
        cbx_crryOutCopino.setSelectedIndex(0);  //cbx_crryOutCopino.setValue = true; 
        $c.gus.cfEnableObjects([tb_crryOutCopino]);
        $c.gus.cfDisableObjects([tb_crryInCopino]);
        ds_resultsCopinoIn.removeAll(); // 반입(COPINO) DataSet 초기화
    }

    if ("" != v_strRegNo) {

        var txt = "";
        v_strRegNo = v_strRegNo.split("-");

        for (i = 0; i < v_strRegNo.length; i++) {
            txt += v_strRegNo[i];
        }


        pCode = txt;
        pName = "";
        pClose = "T";
        pAllSearch = "F";

        udc_ComCode1.setSelectId("retrieveClntNoFind");
        udc_ComCode1.cfCommonPopUp(scwin.udc_ed_srchSelfTransClntNoHide_callBackFunc
                                , pCode // 화면에서의 ??? Code Element의 Value
                                , pName // 화면에서의 ??? Name Element의 Value
                                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                , null // Title순서
                                , null // 보여주는 각 컬럼들의 폭
                                , null // 컬럼중에서 숨기는 컬럼 지정
                                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                                , null // 윈도우 위치 Y좌표
                                , null // 윈도우 위치 X좌표
                                , null // 중복체크여부 ("F")
                                , pAllSearch // 전체검색허용여부 ("F")
                                , "" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );

    }

    acb_selfCls2.setValue("Y");
    acb_selfCls2.setReadOnly(true);  // acb_selfCls2.Enable = false;

    ed_emcId1.setValue(scwin.strEmc);
    ed_emcId2.setValue(scwin.strEmc);
    ed_dpctTransCoId1.setValue(scwin.strId);
    ed_dpctTransCoId2.setValue(scwin.strId);
    ed_transDstFrom1.setValue("6P10");
    ed_transDstTo2.setValue("6P10");
    ed_transDstFrom1.setReadOnly(true);
    ed_transDstTo2.setReadOnly(true); 
    acb_fullEmptyClsCd2.setValue("4");
    acb_fullEmptyClsCd1.setValue("5");
    acb_expimpClsCd1.setValue("I");
    acb_expimpClsCd2.setValue("I");
    ica_crryinoutDt2.setValue(scwin.dateStr);
    ed_crryinoutHh2.setValue(scwin.dateTime);

    $c.gus.cfDisableObjects([ed_transDstFrom1, ed_transDstTo2, acb_fullEmptyClsCd2]);

    scwin.initComp();
}

scwin.initComp = function() {

    // UDC UpperCase 처리
    var  udcObj = [ed_mchtCd1, ed_mchtCd2];

    for (var i = 0 ; i < udcObj.length ; i++) {
        udcObj[i].unbind('onkeyup');
        udcObj[i].bind('onkeyup', scwin.upperCase);
    }
}

scwin.udc_ed_srchSelfTransClntNoHide_callBackFunc = async function (ret) {

    if (ret != null || ret != "N/A") { 
        ed_srchSelfTransClntNoHide.setValue(ret[0]); 
    } else if (ret == "N/A") {
        ed_srchSelfTransClntNoHide.setValue("");
        await $c.win.alert("DPCT 거래처 등록을 확인해주세요, \n 자가담당자에게 거래처등록을 요청하세요");
        $c.gus.cfDisableObjects([ed_vehclIdCardNo, ed_cntrNo]);
        $c.gus.cfDisableBtn([btn_create, btn_save, btnSelect]);
    }
};

scwin.f_defaultValue = function () {

    // 오더번호 강제 설정
    hid_odrNo1.setValue("9999999999999");
    hid_odrNo2.setValue("9999999999999");

    // 순번 설정
    hid_seq1.setValue(0);
    hid_seq2.setValue(0);

    // 반입/반출구분, 반출입구분 설정
    hid_crryinCrryoutCls1.setValue("1"); // 반출 (1)
    hid_crryinCrryoutCls2.setValue("2"); // 반입 (2)

    hid_crryinoutCls1.setValue("1"); // 반출 (1)
    hid_crryinoutCls2.setValue("2"); // 반입 (2)

    // 모선입항년도 설정
    ed_vsslArrvlportYr1.setValue(scwin.strCurYear);
    ed_vsslArrvlportYr2.setValue(scwin.strCurYear);

    // 전송구분
    hid_sndClsCd1.setValue(DsConstants.EDI_SND_CLS_CD_SND_WAIT); // EDI전송구분 : 전송대기(0)
    hid_sndClsCd2.setValue(DsConstants.EDI_SND_CLS_CD_SND_WAIT); // EDI전송구분 : 전송대기(0)

    // 전송일시 초기화
    td_sndClsCd1.setValue('');
    td_sndClsCd2.setValue('');
    td_sndDtHh1.setValue('');
    td_sndDtHh2.setValue('');

    // 운송수단
    hid_transCntSht1.setValue("3");
    hid_transCntSht2.setValue("3");


}

scwin.f_create = function () {

    // DataSet 초기화
    ds_search.setEmptyValue(); 

    ds_resultsCopinoOut.removeAll(); // 반출(COPINO) DataSet 초기화
    ds_resultsCopinoOut.insertRow();
    ds_resultsCopinoOut.setRowPosition(0);

    ds_resultsCopinoIn.removeAll(); // 반입(COPINO) DataSet 초기화
    ds_resultsCopinoIn.insertRow();
    ds_resultsCopinoIn.setRowPosition(0);

    // 조회조건 초기화
    scwin.f_FieldClear();

    // 초기값 설정
    scwin.f_defaultValue();

    $c.gus.cfEnableBtnOnly([btn_create]); // 버튼 활성화
    $c.gus.cfEnableBtnOnly([btn_save]); // 버튼 활성화

    cbx_crryInCopino.setValue("Y"); 
    cbx_crryOutCopino.setValue("Y");

    scwin.f_switchTransYn(2);
    scwin.f_switchTransYn(1);

    ed_sealNo2.options.mandatory    = false;
    ed_sealNo2.setReadOnly(false); 
    lbl_sealNo2.removeClass("req");
}

scwin.f_setDsSearchHeader = function () {
    ds_blSearch.removeAll();
    ds_blSearch.insertRow();
    ds_blSearch.getRowPosition(0);
}


scwin.f_Retrieve = async function (gubun) {

    acb_fullEmptyClsCd2.setEventPause(null, true);

    if ((ed_vehclIdCardNo.getValue() == null || ed_vehclIdCardNo.getValue() == "") && (ed_cntrNo.getValue() == null || ed_cntrNo.getValue() == "")) {
        await $c.win.alert("조회시 차량 ID와 CNTR_NO 중 둘중에 하나 기입해야 합니다.");
        return false;
    }

    if (ed_vehclIdCardNo.getValue() != null && ed_vehclIdCardNo.getValue() != "") {
        if (ed_vehclIdCardNo.getValue().length != 8) {
            await $c.win.alert("조회시 차량 ID는 8자리를 기입해야 합니다.");
            return false;
        }
    }

    if (ed_cntrNo.getValue() != null && ed_cntrNo.getValue() != "") {

        if (ed_cntrNo.getValue().length != 11) {
            await $c.win.alert("조회시 컨테이너는 번호는 11자리를 기입해야 합니다.");
            return false;
        }
    }

    if (gubun == null || gubun == "" || gubun == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoIn.removeAll();

        await $c.sbm.execute(sbm_retrieve);

    } else {
        if (cbx_crryInCopino.getValue() != "Y") {
            ds_resultsCopinoIn2.removeAll();
            if (cbx_crryOutCopino.getValue() == "Y") {

                ds_resultsCopinoOut.removeAll();
                ds_resultsCopinoOut.insertJSON(0, ds_resultsCopinoOut2.getAllJSON());

                await $c.sbm.execute(sbm_retrieve2);
            }
        }
        if (cbx_crryOutCopino.getValue() != "Y") {
            ds_resultsCopinoOut2.removeAll();
            if (cbx_crryInCopino.getValue() == "Y") {

                ds_resultsCopinoIn.removeAll();
                ds_resultsCopinoIn.insertJSON(0, ds_resultsCopinoIn2.getAllJSON());

                await $c.sbm.execute(sbm_retrieve2);
            }
        }
    }   
}

scwin.f_Retrieve_callback = function() {

    if (ds_resultsCopinoOut.getRowCount() == 0) {
        ds_resultsCopinoOut.insertRow();
        ds_resultsCopinoOut.setRowPosision(0);
    } else if (ds_resultsCopinoIn.getRowCount() == 0) {
        ds_resultsCopinoIn.insertRow();
        ds_resultsCopinoIn.setRowPosition(0);
    }

    scwin.f_defaultValue();

    acb_fullEmptyClsCd2.setEventPause(null, false);
    acb_expimpClsCd2.setValue("I");

    ed_transDstFrom1.setValue("6P10");
    ed_transDstTo2.setValue("6P10");
    ed_transDstFrom1.setReadOnly(true);
    ed_transDstTo2.setReadOnly(true); 
    acb_fullEmptyClsCd2.setValue("4");
    acb_fullEmptyClsCd1.setValue("5");
    acb_expimpClsCd1.setValue("I");
    acb_expimpClsCd2.setValue("I");

    $c.gus.cfDisableObjects([ed_transDstFrom1, ed_transDstTo2, acb_fullEmptyClsCd2]);
}   

scwin.f_RetrieveBl = function (blNo, shpCoNm, cntrNo) {

    // B/L번호저장
    ds_blSearch.setCellData(0, "doNo", blNo);
    ds_blSearch.setCellData(0, "shpCoNm", shpCoNm);
    ds_blSearch.setCellData(0, "cntrNo", cntrNo);

    if (ds_blSearch.getCellData(0, "shpCoNm") == "") { 
        $c.win.alert(scwin.MSG_OP_INF_002); // D/O, B/L을 자동으로 가져오려면\nOPERATOR는 필수입력사항입니다.
        return; 
    } 

    if (ds_blSearch.getCellData(0, "cntrNo") == "") {  
        $c.win.alert(scwin.MSG_OP_INF_001); // D/O, B/L을 자동으로 가져오려면\n컨테이너번호는 필수입력사항입니다.
        return;
    } 

    $c.sbm.execute(sbm_retrieveBl); 
}

scwin.f_RetrieveDo = function (cntrNo) {
    // B/L번호저장

    $c.sbm.execute(sbm_retrieveDoNo);
}


scwin.f_validate = async function () {

    if (cbx_crryOutCopino.getValue() == "Y") { 
        //반출
        if (ds_resultsCopinoOut.getRowCount() > 0 && !$c.gus.cfIsNull(ds_resultsCopinoOut.getCellData(0, "transDstFrom"))) {

            if ($c.gus.cfIsNull(acb_expimpClsCd1.getValue())) {
                await $c.win.alert("수출입구분을 선택 하세요.");
                return false;
            }
            if ($c.gus.cfIsNull(ed_vehclNoFrtcarNo1.getValue())) {
                await $c.win.alert("차량ID를 반드시 입력하세요 .");
                return false;
            }

            if ($c.gus.cfIsNull(ed_tmlVsslPortcnt1.getValue())) {
                await $c.win.alert("모선/항차를 반드시 입력하세요 .");
                return false;
            }

            if ($c.gus.cfIsNull(ed_cntrNo1.getValue())) {
                await $c.win.alert("컨테이너번호를 반드시 입력하세요 .");
                return false;
            }

            if ($c.gus.cfIsNull(ed_shpCoCd1.getValue())) {
                await $c.win.alert("OPERATOR를 반드시 입력하세요 .");
                return false;
            }

            if ($c.gus.cfIsNull(acb_fullEmptyClsCd1.getValue())) {
                await $c.win.alert("F/E를 반드시 선택하세요 .");
                return false;
            }


            if (ed_transDstFrom1.getValue() == "6P10" && ed_transDstTo1.getValue() == "6P26" && acb_expimpClsCd1.getValue() == "I"
                && (ed_shpCoCd1.getValue() == "EMS" || ed_shpCoCd1.getValue() == "EMC" || ed_shpCoCd1.getValue() == "EMA" || ed_shpCoCd1.getValue() == "EVER")
                && acb_tsCls1.getValue() == "14") { 

                // 6P10 --> 한진 통과

            } else {

                if ($c.gus.cfIsNull(ed_blNo1.getValue())) {
                    await $c.win.alert("BL/NO를 반드시 입력하세요 .");
                    return false;
                }

                if ($c.gus.cfIsNull(ed_doNo1.getValue())) {
                    await $c.win.alert("DO/NO를 반드시 입력하세요 ....");
                    return false;
                }
            }

            if ($c.gus.cfIsNull(ica_crryinoutDt1.getValue())) {
                await $c.win.alert("반입일시를 입력하세요 .");
                return false;
            } 

            if ($c.gus.cfIsNull(ed_crryinoutHh1.getValue())) { 
                await $c.win.alert("반입일시를 입력하세요 .");
                return false;
            } 

            if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) {
                // 출발지 설정
                hid_startPoint1.setValue(ed_transDstFrom1.getValue()); 

                if (ed_transDstFrom1.getValue() == "6P42") { 
                    // CY 가 울산정일부두(6P42) 인 경우 : 화주 필수 입력
                    ed_mchtCd1.mandatoryCode = "true";
                    lbl_mchtCd1.addClass("req");

                    // CY 가 울산정일부두(6P42) 인 경우 : 컨테이너번호 옵션
                    ed_cntrNo1.options.mandatory    = false;
                    ed_cntrNo1.setValue(""); 
                    lbl_cntrNo1.removeClass("req");

                } else if (ed_transDstFrom1.getValue() == "6P14" || ed_transDstFrom1.getValue() == "6P12") {
                    // CY 가 허치슨감만T(6P14)/HBCT(6P12) 인 경우 : 컨테이너번호 <- ZZZZ1234567
                    if (acb_fullEmptyClsCd2.getValue() == "4") {
                        ed_cntrNo1.options.mandatory    = true; 
                        ed_cntrNo1.setValue("ZZZZ1234567");  
                        lbl_cntrNo1.addClass("req"); 
                    }
                } else if (ed_transDstFrom1.getValue() == "6P42") { 
                    // CY 가 울산6부두[UCTC] (6P36) 인 경우 : EMPTY 
                    ed_cntrNo1.options.mandatory    = true; 
                    ed_cntrNo1.setValue("EMPTY");   
                    lbl_cntrNo1.addClass("req");
                } else {
                    // 기타 작업장 : 컨테이너 필수 입력
                    ed_cntrNo1.options.mandatory    = true; 
                    lbl_cntrNo1.addClass("req");
                }

                if (ed_transDstFrom1.getValue() == "6P13") {
                } else {
                }
            }


            if (ed_transDstFrom1.getValue().substring(1, 2) == DsConstants.WRK_PL_CLS_CD_PORT) {
                // CY 가 부두인 경우 : OPERATOR 필수 입력
                lbl_shpCoCd1.addClass("req");
            }


            if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) { 
                // 수신자 <- 출발지 설정
                hid_rcv1.setValue(ed_transDstFrom1.getValue()); 
            } else {
                hid_rcv1.setValue("");
            }

            if (ed_tmlVsslPortcnt1.getValue().length == 5) {
                ds_resultsCopinoOut.setCellData(0, "tmlVsslPortcnt", ed_tmlVsslPortcnt1.getValue().substring(0, 3) + " " + ed_tmlVsslPortcnt1.getValue().substring(3, 5));
            }

            //<----
            hid_crryinoutDtmMint1.setValue(ica_crryinoutDt1.getValue() + ed_crryinoutHh1.getValue());
            //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
            if (ds_resultsCopinoOut.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM
                && ds_resultsCopinoOut.getCellData(0, "vehclIdCardNo") == "") {
                await $c.win.alert("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다"); 
                return false; 
            }
            if (cbx_crryOutCopino.getValue() == "Y") { 
                //$c.gus.cfCopyDataSet(ds_resultsCopinoOut, ds_resultsCopinoOut2, v_features);

                ds_resultsCopinoOut2.removeAll();
                ds_resultsCopinoOut2.insertJSON(0, ds_resultsCopinoOut.getAllJSON());
            }

            if (cbx_crryOutCopino.getValue() != "Y") { 
                ds_resultsCopinoOut2.removeAll(); 
            }

            if (ed_vehclNoFull1.getValue().length != 9) { 
                await $c.win.alert("차량번호는 FULL NAME을 정확히 입력하세요1 예)경기98자1234"); 
                return false; 
            } else { 
                //가운데 숫자체크
                if (Number(ed_vehclNoFull1.getValue().substring(2, 4)) >= 0 && Number(ed_vehclNoFull1.getValue().substring(2, 4)) <= 99 && ed_vehclNoFull1.getValue().substring(2, 4).length == 2) { 
                    //alert("OK");
                } else {
                    await $c.win.alert("세번째 네번째는 숫자이어야 합니다. ");
                    return false;
                }
                //마지막 네자리 숫자 체트
                if (Number(ed_vehclNoFull1.getValue().substring(5, 10)) >= 0 && Number(ed_vehclNoFull1.getValue().substring(5, 10)) <= 9999 && ed_vehclNoFull1.getValue().substring(5, 10).length == 4) {
