scwin.sbm_retrieve_submitdone = function (e) {

    $c.gus.cfEnableBtnOnly([btn_create, btn_save]); // 버튼 활성화	

    if (ds_resultsCopinoOut.getRowCount() == 0 || ds_resultsCopinoIn.getRowCount() == 0) { 
        $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    // ds_resultsCopinoOut 처리
    for (var i = 0; i < ds_resultsCopinoOut.getRowCount(); i++) { 

        ds_resultsCopinoOut.setRowPosition(i);

        var sndDt1 = (ds_resultsCopinoOut.getCellData(i, "sndDt") == "") ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(i, "sndDt"), "####/##/##");
        var sndHh1 = (ds_resultsCopinoOut.getCellData(i, "sndHh") == "") ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(i, "sndHh"), "##:##:##");

        td_sndDtHh1.setValue(sndDt1 + " " + sndHh1);     

        td_sndClsCd1.setStyle('color', '');
        if (ds_resultsCopinoOut.getCellData(i, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE) {
            td_sndClsCd1.setValue("전송완료");
            td_sndClsCd1.setStyle('color', 'red');
        } else if (ds_resultsCopinoOut.getCellData(i, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND) {
            td_sndClsCd1.setValue("사후전송"); 
            td_sndClsCd1.setStyle('color', 'red');
        } else if (ds_resultsCopinoOut.getCellData(i, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN) {
            td_sndClsCd1.setValue("필수입력오류"); 
            td_sndClsCd1.setStyle('color', 'red');
        } else if (ds_resultsCopinoOut.getCellData(i, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT) {
            td_sndClsCd1.setValue("전송대기"); 
            td_sndClsCd1.setStyle('color', 'red');
        } else {
            td_sndClsCd1.setValue("미등록"); 
            td_sndClsCd1.setStyle('color', 'red');
        }

        //[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
        if (ds_resultsCopinoOut.getCellData(i, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD && ds_resultsCopinoOut.getCellData(i, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD) {
            $c.gus.cfDisableObjects([ed_vehclNoFrtcarNo1]); 
        }

        var crryinoutDtmMint1_Date = hid_crryinoutDtmMint1.getValue();

        ica_crryinoutDt1.setValue(crryinoutDtmMint1_Date.substring(0, 8));      //YYYY/MM/DD 
        ed_crryinoutHh1.setValue(crryinoutDtmMint1_Date.substring(8, 12));       //HH:mm 
    }


    // ds_resultsCopinoIn 처리
	for (var i = 0; i < ds_resultsCopinoIn.getRowCount(); i++) {
        ds_resultsCopinoIn.setRowPosition(i);

		//반입
        var sndDt2      = (ds_resultsCopinoIn.getCellData(0, "sndDt") == "") ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoIn.getCellData(0, "sndDt"), "####/##/##");
        var sndHh2      = (ds_resultsCopinoIn.getCellData(0, "sndHh") == "") ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoIn.getCellData(0, "sndHh"), "##:##:##"); 

        td_sndDtHh2.setValue(sndDt2 + " " + sndHh2); 

		if( ds_resultsCopinoIn.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
			td_sndClsCd2.setValue("전송완료");
            td_sndClsCd2.setStyle('color', 'red');
		} else if( ds_resultsCopinoIn.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND ) {
			td_sndClsCd2.setValue("사후전송");  
            td_sndClsCd2.setStyle('color', 'red');
		} else if( ds_resultsCopinoIn.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN ) {
			td_sndClsCd2.setValue("필수입력오류");  
            td_sndClsCd2.setStyle('color', 'red');
		} else if( ds_resultsCopinoIn.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
			td_sndClsCd2.setValue("전송대기");  
            td_sndClsCd2.setStyle('color', 'red');
		} else {
			td_sndClsCd2.setValue("미등록"); 
            td_sndClsCd2.setStyle('color', 'red');
		}

		//[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
		if ( ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD 
		  && ds_resultsCopinoIn.getCellData(0, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD ) {
			$c.gus.cfDisableObjects([ed_vehclNoFrtcarNo2]);
		} 

		var  crryinoutDtmMint2_Date = hid_crryinoutDtmMint2.getValue(); 

        ica_crryinoutDt2.setValue(crryinoutDtmMint2_Date.substring(0, 8));      //YYYY/MM/DD 
        ed_crryinoutHh2.setValue(crryinoutDtmMint2_Date.substring(8, 12));       //HH:mm 
	}

    scwin.f_Retrieve_callback();
};

