};


scwin.sbm_retrieveBl_submitdone = async function (e) { 

    if (ds_blSearch.getRowCount() > 0 && ds_blSearch.getCellData(0, "doNo") != "") { 
        //반출
        if (cbx_crryOutCopino.getValue() == "Y") { 
            ed_blNo1.setValue(ds_blSearch.getCellData(0, "doNo")); 
            ed_doNo1.setValue(ds_blSearch.getCellData(0, "doNo")); 
        } else if (cbx_crryInCopino.getValue() == "Y") {
            ed_blNo2.setValue(ds_blSearch.getCellData(0, "doNo")); 
            ed_doNo2.setValue(ds_blSearch.getCellData(0, "doNo")); 
