    } else {
        await $c.win.alert(scwin.MSG_OP_INF_003); //존재하지 않는 B/L입니다.\n다시 확인하여 입력하십시오.

        if (cbx_crryOutCopino.getValue() == "Y") {
            ed_blNo1.setValue(""); 
            ed_doNo1.setValue(""); 
        } else if (cbx_crryInCopino.getValue() == "Y") {
            ed_blNo2.setValue(""); 
            ed_doNo2.setValue(""); 
        }
    }	
};

scwin.sbm_retrieveDoNo_submitdone = function (e) {

    if (ds_lastDoDTO.getRowCount() > 0 && ds_lastDoDTO.getCellData(0, "doNo") != "") {
        ds_lastDoDTO.setRowPosition(0);
        //반출
        if (cbx_crryOutCopino.getValue() == "Y") {
            ed_blNo1.setValue(ds_lastDoDTO.getCellData(0, "doNo"));
            ed_doNo1.setValue(ds_lastDoDTO.getCellData(0, "doNo"));
            ed_shpCoCd1.setValue(ds_lastDoDTO.getCellData(0, "doOutbrShpCo"));
        } else if (cbx_crryInCopino.getValue() == "Y") {
            ed_blNo2.setValue(ds_lastDoDTO.getCellData(0, "doNo"));
            ed_doNo2.setValue(ds_lastDoDTO.getCellData(0, "doNo"));
            ed_shpCoCd2.setValue(ds_lastDoDTO.getCellData(0, "doOutbrShpCo"));
            hid_cntrRtrnDt2.setValue(ds_lastDoDTO.getCellData(0, "cntrRtrnDt"));
        }
    } else {
        $c.win.alert(scwin.MSG_OP_INF_003); //존재하지 않는 B/L입니다.\n다시 확인하여 입력하십시오.
        if (cbx_crryOutCopino.getValue() == "Y") {
            ed_blNo1.setValue("");
            ed_doNo1.setValue("");
            ed_shpCoCd1.setValue("");
        } else if (cbx_crryInCopino.getValue() == "Y") {
            ed_blNo2.setValue("");
            ed_doNo2.setValue("");
            ed_shpCoCd2.setValue("");
        }
    }	
};


