scwin.ed_vehclNoFull1_onblur = async function (e) {

    ed_vehclNoFull1.setEventPause(null, true);

    if (!await $c.gus.cfValidate([ed_vehclNoFull1])) {
        ed_vehclNoFull1.setValue("");
        ed_vehclNoFull1.blur();
    }
    //[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
    if (ds_resultsCopinoOut.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
        && ds_resultsCopinoOut.getCellData(0, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD
        && ds_resultsCopinoOut.getCellData(0, "wrkStpCd") != ed_vehclNoFull1.getValue()) {

        $c.gus.cfEnableObjects([ed_vehclNoFrtcarNo1]);
    }

    ed_vehclNoFull1.setEventPause(null, false);
};

scwin.ed_vehclNoFull2_onblur = async function (e) {

    ed_vehclNoFull2.setEventPause(null, true);

    if (!await $c.gus.cfValidate([ed_vehclNoFull2])) {
        ed_vehclNoFull2.setValue("");
        ed_vehclNoFull2.blur();
    }

    //[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
    if (ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
        && ds_resultsCopinoIn.getCellData(0, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD
        && ds_resultsCopinoIn.getCellData(0, "wrkStpCd") != ed_vehclNoFull2.getValue()) {

        $c.gus.cfEnableObjects([ed_vehclNoFrtcarNo2]);
    }

    ed_vehclNoFull2.setEventPause(null, false);
};

scwin.ed_vehclNoFrtcarNo1_onblur = async function (e) {
    //차량id번호가 없는 경우 조회로직 안타도록함
    if (ed_vehclNoFrtcarNo1.getValue().trim() == "") return;

    ds_search.set("vehclIdCardNo", ed_vehclNoFrtcarNo1.getValue().trim());
    await $c.sbm.execute(sbm_retrieve3);
    if (ds_lastCarInOutDTO.getRowCount() > 0) {
        for (var i = 0; i < ds_lastCarInOutDTO.getRowCount(); i++) {
            if (ds_lastCarInOutDTO.getCellData(i, "crryinCrryoutCls") == "3" && ed_vehclNoFrtcarNo1.getValue() != "") {
                ed_vehclNoFull1.setValue(ds_lastCarInOutDTO.getCellData(i, "vehclNoFull")); 
            }
        }
    }
    ed_vehclNoFull1.focus(); 

}; 

