scwin.ed_frzTemper2_onblur = function (e) {

    if (ed_frzTemper2.getValue().trim() == '') {
        ed_frzTemper2.setValue("");
    } else {
        if (hid_sizTyp2.getValue().substring(2, 2) == "RF" || hid_sizTyp2.getValue().substring(2, 2) == "RH") {
            if (ed_frzTemper2.getValue() == "") {
                hid_temperCls2.setValue("DRY");
                ed_rmk3.setValue(DsConstants.EDI_TEMPER_CLS_DRY);

            } else {
                hid_temperCls2.setValue("CEL");

                ed_rmk3.setValue(DsConstants.EDI_TEMPER_CLS_CEL);
            }

        }
    }
};

scwin.acb_expimpClsCd1_onchange = function (info) {
    if (acb_expimpClsCd1.getValue() == "I") {
        // 수입
        ed_bookingNo1.setReadOnly(true); // B/K 번호
        ed_blNo1.setReadOnly(false);     // BL 번호
        ed_doNo1.setReadOnly(false);     // D/o 번호
        ed_bookingNo1.setValue("");

    } else if (acb_expimpClsCd1.getValue() == "E") {
        // 수출
        ed_bookingNo1.setReadOnly(false); // B/K 번호
        ed_blNo1.setReadOnly(true);       // BL 번호
        ed_doNo1.setReadOnly(true);       // D/o 번호
        ed_bookingNo1.setValue("");        
    } 
};

scwin.acb_fullEmptyClsCd1_onchange = function (info) {
    if (ds_resultsCopinoOut.getRowCount() > 0) {

        if (acb_fullEmptyClsCd1.getValue() == "4") {
            // 4 : EMPTY
            ed_sealNo1.setValue(" ");
            ed_sealNo1.setReadOnly(true); // SEAL NO
        } else if (acb_fullEmptyClsCd1.getValue() == "5") {
            // 5 : FULL
            ed_sealNo1.setReadOnly(false); // SEAL NO
        }
    }
};

scwin.acb_expimpClsCd2_onchange = function (info) {

    if (acb_expimpClsCd2.getValue() == "I") {
        // 수입
        ed_bookingNo2.setReadOnly(true); // B/K 번호
        ed_doNo2.setReadOnly(false);     // D/o 번호
        ed_blNo2.setReadOnly(false);     // BL 번호

    } else if (acb_expimpClsCd2.getValue() == "E") {
        // 수출
        ed_bookingNo2.setReadOnly(false); // B/K 번호
        ed_blNo2.setReadOnly(true);       // BL 번호
        ed_doNo2.setReadOnly(true);       // D/o 번호
        ed_blNo2.setValue("");
    } else {
        ed_bookingNo2.setReadOnly(false);  // B/K 번호
    }

};

scwin.acb_fullEmptyClsCd2_onchange = function (info) {

    if (ds_resultsCopinoIn.getRowCount() > 0) {
        if (acb_fullEmptyClsCd2.getValue() == "4") {
            ed_sealNo2.setValue(" ");
            // EMPTY 인 경우 : WEIGHT 선택
            ed_totWt2.options.mandatory = false;
            lbl_totWt2.removeClass("req");
        } else if (acb_fullEmptyClsCd2.getValue() == "5") {
            // 5 : FULL
            ed_sealNo2.setReadOnly(false); // SEAL NO
            // FULL 인 경우 : WEIGHT 필수
            ed_totWt2.options.mandatory = true;
            lbl_totWt2.addClass("req");
        } 
    }
};  

scwin.acb_dangerCd2_onchange = function (info) {

    if (acb_dangerCd2.getValue() == "D") {
        ed_dchrPort2.setValue("ODDMD");

    } else if (acb_dangerCd2.getValue() == "C") {
        // 5 : FULL
        ed_dchrPort2.setValue("ZZCLN");

    } else {
        // E/F 구분을(를) 선택하십시오.
        ed_dchrPort2.setValue("ZZZZZ");
    }
};


