scwin.upperCase = function(e) {
    var obj     = window[e.target.id];

    if (obj.setValue) {
        var oldVal = obj._oldValue;
        obj.setValue(obj.getValue().toUpperCase());
        obj._oldValue = oldVal;
    }
}
